// Translate one PVS appointment row into the EINS canonical envelope.
// Replace field references with your PVS's actual JSON paths.
//
// Required: pvsPatientId, pvsAppointmentId, scheduledAt
// Optional: treatmentCode/Label, locationCode/Label, bemerkung
//
// The event ID must be stable per source row (de-duplication key on the
// portal side). Use the PVS's own row id + modified-at where possible.
const row = $input.first().json;
const event = {
  kind: 'AppointmentCreated',
  clinicId: $vars.CLINIC_ID,
  bridgeSource: 'n8n_custom',
  pvsExternalEventId: `n8n:appt:${row.id}`,
  occurredAt: row.scheduledAt,
  pvsPatientId: String(row.patientId),
  pvsAppointmentId: String(row.id),
  scheduledAt: row.scheduledAt,
  treatmentCode: row.treatmentCode ?? undefined,
  treatmentLabel: row.treatmentName ?? undefined,
  bemerkung: row.comment ?? undefined,
};
return { json: event };

// Sign the body with the per-clinic HMAC secret stored in n8n credentials.
const body = JSON.stringify($input.first().json);
const crypto = require('crypto');
const sig = `sha256=${crypto.createHmac('sha256', $vars.EINS_PVS_SECRET).update(body).digest('hex')}`;
return { json: { body, sig } };
